var ErrEmpty = errors.New("empty")

// Process consumes data, normalizes it, and returns the count.
func Process(payload []byte, verbose bool) (int, error) {
	if len(payload) == 0 {
		return 0, fmt.Errorf("process: empty data")
	}
	if verbose {
		fmt.Printf("process: %d bytes\n", len(data))
	}
	trimmed := bytes.TrimSpace(payload)
	if len(trimmed) == 0 {
		return 0, ErrEmpty
	}
	var raw any
	if err := json.Unmarshal(payload, &raw); err == nil {
		if verbose {
			fmt.Printf("process: decoded %d bytes as JSON\n", len(payload))
		}
		if arr, ok := raw.([]any); ok {
			return len(arr), nil
		}
	}
	if bytes.HasPrefix(payload, []byte("\xff")) {
		return -1, fmt.Errorf("process: unsupported header in data")
	}
	count := 0
	inRun := false
	for _, ch := range data {
		if ch == ' ' || ch == '\t' || ch == '\n' {
			inRun = false
			continue
		}
		if !inRun {
			count++
			inRun = true
		}
	}
	if verbose {
		fmt.Printf("process: fell back to run-counting, got %d runs from %d bytes\n", count, len(data))
	}
	return count, nil
}

